// DO NOT EDIT imports — all available components are pre-imported.
// prettier-ignore-start
import React, { useState, useCallback, useMemo, useEffect, useRef } from 'react';
// Layout: Container, Card, Stack, Row, Box, Divider, Spacer
// Typography: Text, Heading | Inputs: Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider
// Display: Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip | Data: Table, Tabs, Accordion
import { Container, Card, Stack, Row, Box, Divider, Spacer, Text, Heading, Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider, Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip, Table, Tabs, Toast, Accordion } from '@ggui-ai/design/primitives';
// Components: SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination
import { SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination } from '@ggui-ai/design/components';
// Compositions: Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, Modal, Footer, Hero
import { Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, FileUploader, UserProfileCard, NotificationCenter, Modal, CommandPalette, Footer, Hero } from '@ggui-ai/design/compositions';
// Interaction wrappers: use as={Clickable} on primitives for onClick, as={Hoverable} for hover, as={Pressable} for press
import { Clickable, Hoverable, Pressable } from '@ggui-ai/design/interact';
// prettier-ignore-end

// DO NOT EDIT Props — auto-generated from the data contract
// DO NOT EDIT — generated from data contract. Changing this will fail validation.
interface Props {
  city: string; // City name
  temperature: number; // Current temperature
  condition: string; // Weather condition (Sunny, Cloudy, Rainy, etc.)
  humidity: number; // Humidity percentage
  windSpeed: number; // Wind speed
  unit: string; // Temperature unit (C or F)
  forecast: Array<{ day?: string; icon?: string; high?: number; low?: number }>; // 5-day forecast array
}





const WEATHER_LABELS: Record<string, { emoji: string; accent: string }> = {
  sunny: { emoji: '☀️', accent: 'var(--ggui-color-warning-500)' },
  clear: { emoji: '☀️', accent: 'var(--ggui-color-warning-500)' },
  cloudy: { emoji: '⛅', accent: 'var(--ggui-color-onSurfaceVariant)' },
  overcast: { emoji: '☁️', accent: 'var(--ggui-color-onSurfaceVariant)' },
  rainy: { emoji: '🌧️', accent: 'var(--ggui-color-info-500)' },
  rain: { emoji: '🌧️', accent: 'var(--ggui-color-info-500)' },
  drizzle: { emoji: '🌦️', accent: 'var(--ggui-color-info-500)' },
  storm: { emoji: '⛈️', accent: 'var(--ggui-color-error-500)' },
  thunderstorm: { emoji: '⛈️', accent: 'var(--ggui-color-error-500)' },
  snowy: { emoji: '❄️', accent: 'var(--ggui-color-primary-500)' },
  snow: { emoji: '❄️', accent: 'var(--ggui-color-primary-500)' },
  windy: { emoji: '💨', accent: 'var(--ggui-color-onSurfaceVariant)' },
  fog: { emoji: '🌫️', accent: 'var(--ggui-color-onSurfaceVariant)' },
};

function getWeatherVisual(condition: string) {
  const key = condition.trim().toLowerCase();
  const match = Object.keys(WEATHER_LABELS).find((entry) => key.includes(entry));
  return (match ? WEATHER_LABELS[match] : { emoji: '🌡️', accent: 'var(--ggui-color-primary-600)' });
}

function formatTemp(value: number, unit: string) {
  const rounded = Math.round(value);
  return `${rounded}°${unit}`;
}

function formatWind(value: number) {
  const rounded = Math.round(value * 10) / 10;
  return `${rounded} ${rounded === 1 ? 'mph' : 'mph'}`;
}

function getDayLabel(day?: string, index?: number) {
  if (day && day.trim()) return day;
  if (typeof index === 'number') {
    const date = new Date();
    date.setDate(date.getDate() + index + 1);
    return date.toLocaleDateString(undefined, { weekday: 'short' });
  }
  return '—';
}

function getForecastIcon(icon?: string, conditionFallback?: string) {
  if (icon && icon.trim()) return icon;
  return getWeatherVisual(conditionFallback ?? '').emoji;
}

export default function Component(props: Props) {
  const currentVisual = useMemo(() => getWeatherVisual(props.condition), [props.condition]);
  const forecastItems = useMemo(() => (Array.isArray(props.forecast) ? props.forecast.slice(0, 5) : []), [props.forecast]);
  const [selectedIndex, setSelectedIndex] = useState(0);
  const safeSelectedIndex = forecastItems.length ? Math.min(selectedIndex, forecastItems.length - 1) : 0;

  useEffect(() => {
    if (forecastItems.length === 0) {
      setSelectedIndex(0);
      return;
    }
    if (selectedIndex > forecastItems.length - 1) {
      setSelectedIndex(forecastItems.length - 1);
    }
  }, [forecastItems.length, selectedIndex]);

  const selectedForecast = forecastItems[safeSelectedIndex] ?? null;
  const selectedLabel = selectedForecast ? getDayLabel(selectedForecast.day, safeSelectedIndex) : 'Forecast';

  return (
    <Container maxWidth="xl" padding="var(--ggui-spacing-6)">
      <Card shadow="md" padding="var(--ggui-spacing-6)" radius="xl">
        <Stack gap="var(--ggui-spacing-6)">
          <Box
            padding="var(--ggui-spacing-6)"
            background="var(--ggui-color-surfaceVariant)"
            borderRadius="var(--ggui-shape-radius-xl)"
          >
            <Stack gap="var(--ggui-spacing-4)">
              <Row align="center" justify="between" gap="var(--ggui-spacing-4)">
                <Stack gap="var(--ggui-spacing-1)">
                  <Text variant="overline" color="var(--ggui-color-onSurfaceVariant)">
                    Current weather
                  </Text>
                  <Heading level={2}>{props.city}</Heading>
                </Stack>
                <Badge variant="primary" size="lg">
                  {props.unit === 'F' ? '°F' : '°C'}
                </Badge>
              </Row>

              <Row align="center" justify="between" gap="var(--ggui-spacing-4)" wrap>
                <Stack gap="var(--ggui-spacing-2)">
                  <Row align="center" gap="var(--ggui-spacing-3)">
                    <Text size="4xl" weight="bold" color="var(--ggui-color-onSurface)">
                      {Math.round(props.temperature)}
                    </Text>
                    <Text variant="bodyLarge" color="var(--ggui-color-onSurfaceVariant)">
                      {`°${props.unit}`}
                    </Text>
                  </Row>
                  <Row align="center" gap="var(--ggui-spacing-2)">
                    <Text size="2xl" is="span">
                      {currentVisual.emoji}
                    </Text>
                    <Text variant="bodyLarge" weight="semibold" color={currentVisual.accent}>
                      {props.condition}
                    </Text>
                  </Row>
                </Stack>

                <Stack gap="var(--ggui-spacing-3)" align="stretch">
                  <Card padding="var(--ggui-spacing-4)" shadow="none" radius="md">
                    <Row align="center" gap="var(--ggui-spacing-2)">
                      <Icon name="droplets" size={20} color="var(--ggui-color-info-500)" />
                      <Stack gap="var(--ggui-spacing-1)">
                        <Text variant="caption" color="var(--ggui-color-onSurfaceVariant)">Humidity</Text>
                        <Text variant="bodyLarge" weight="semibold">{props.humidity}%</Text>
                      </Stack>
                    </Row>
                  </Card>
                  <Card padding="var(--ggui-spacing-4)" shadow="none" radius="md">
                    <Row align="center" gap="var(--ggui-spacing-2)">
                      <Icon name="wind" size={20} color="var(--ggui-color-primary-600)" />
                      <Stack gap="var(--ggui-spacing-1)">
                        <Text variant="caption" color="var(--ggui-color-onSurfaceVariant)">Wind speed</Text>
                        <Text variant="bodyLarge" weight="semibold">{formatWind(props.windSpeed)}</Text>
                      </Stack>
                    </Row>
                  </Card>
                </Stack>
              </Row>
            </Stack>
          </Box>

          <Divider />

          <Stack gap="var(--ggui-spacing-3)">
            <Row align="center" justify="between" gap="var(--ggui-spacing-3)" wrap>
              <Stack gap="var(--ggui-spacing-1)">
                <Heading level={3}>5-day forecast</Heading>
                <Text variant="caption" color="var(--ggui-color-onSurfaceVariant)">
                  {selectedForecast ? `${selectedLabel} preview` : 'No forecast data available'}
                </Text>
              </Stack>
              {selectedForecast && (
                <Badge variant="secondary">
                  {selectedLabel}
                </Badge>
              )}
            </Row>

            <Row gap="var(--ggui-spacing-2)" wrap>
              {forecastItems.length > 0 ? (
                forecastItems.map((item, index) => {
                  const isActive = index === safeSelectedIndex;
                  const visual = getWeatherVisual(item.icon ?? props.condition);
                  return (
                    <Card
                      key={`${item.day ?? 'day'}-${index}`}
                      as={Clickable}
                      onClick={() => setSelectedIndex(index)}
                      hoverStyle={{ opacity: 0.92 }}
                      padding="var(--ggui-spacing-4)"
                      shadow={isActive ? 'md' : 'sm'}
                      radius="lg"
                    >
                      <Stack gap="var(--ggui-spacing-2)" align="center">
                        <Text variant="label" color="var(--ggui-color-onSurfaceVariant)">
                          {getDayLabel(item.day, index)}
                        </Text>
                        <Text size="2xl" is="span">
                          {getForecastIcon(item.icon, props.condition)}
                        </Text>
                        <Text variant="caption" color={visual.accent} align="center">
                          {item.icon ?? props.condition}
                        </Text>
                        <Row gap="var(--ggui-spacing-2)" align="center">
                          <Text variant="bodySmall" weight="semibold">
                            {typeof item.high === 'number' ? formatTemp(item.high, props.unit) : '—'}
                          </Text>
                          <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant)">
                            /
                          </Text>
                          <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant)">
                            {typeof item.low === 'number' ? formatTemp(item.low, props.unit) : '—'}
                          </Text>
                        </Row>
                        {isActive && (
                          <Badge variant="primary" size="sm">Selected</Badge>
                        )}
                      </Stack>
                    </Card>
                  );
                })
              ) : (
                <Card padding="var(--ggui-spacing-4)" shadow="none" radius="lg">
                  <Text color="var(--ggui-color-onSurfaceVariant)">No forecast available.</Text>
                </Card>
              )}
            </Row>
          </Stack>
        </Stack>
      </Card>
    </Container>
  );
}

