import React, { useState, useCallback, useMemo, useEffect, useRef } from 'react';
// Layout: Container, Card, Stack, Row, Box, Divider, Spacer
// Typography: Text, Heading | Inputs: Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider
// Display: Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip | Data: Table, Tabs, Accordion
import { Container, Card, Stack, Row, Box, Divider, Spacer, Text, Heading, Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider, Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip, Table, Tabs, Toast, Accordion } from '@ggui-ai/design/primitives';
// Components: SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination
import { SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination } from '@ggui-ai/design/components';
// Compositions: Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, Modal, Footer, Hero
import { Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, FileUploader, UserProfileCard, NotificationCenter, Modal, CommandPalette, Footer, Hero } from '@ggui-ai/design/compositions';
// Interaction wrappers: use as={Clickable} on primitives for onClick, as={Hoverable} for hover, as={Pressable} for press
import { Clickable, Hoverable, Pressable } from '@ggui-ai/design/interact';
import { useAction } from '@ggui-ai/wire';
// prettier-ignore-end

// DO NOT EDIT Props — auto-generated from the data contract
// DO NOT EDIT — generated from data contract. Changing this will fail validation.
interface Props {
  featureOptions: string[]; // Available feature options for the checkbox step
  satisfactionLabels: string[]; // Labels for satisfaction rating (e.g., Very Unsatisfied to Very Satisfied)
}

// DO NOT EDIT — action payload types generated from action contract.
/** Action payload: Called with all collected answers as a structured object */
type ActionSubmitPayload = { name: string; email: string; satisfaction: number; features: string[]; comments: string };





// Place helper components here if needed
const isValidEmail = (value: string) => /^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(value.trim());

function StepHeader(props: { currentStep: number; totalSteps: number }) {
  return (
    <Stack gap="var(--ggui-spacing-2)">
      <Row align="center" justify="between">
        <Text variant="overline" color="var(--ggui-color-primary-700)">
          Survey progress
        </Text>
        <Text variant="caption" color="var(--ggui-color-onSurfaceVariant)">
          Step {props.currentStep} of {props.totalSteps}
        </Text>
      </Row>
      <Progress value={props.currentStep} max={props.totalSteps} showLabel />
    </Stack>
  );
}

function AnswerReview(props: {
  name: string;
  email: string;
  satisfactionLabel: string;
  features: string[];
  comments: string;
}) {
  return (
    <Stack gap="var(--ggui-spacing-3)">
      <Heading level={4}>Review your answers</Heading>
      <Card shadow="none" border radius="md" padding="var(--ggui-spacing-4)">
        <Stack gap="var(--ggui-spacing-3)">
          <Box>
            <Text variant="caption" color="var(--ggui-color-onSurfaceVariant)">Name</Text>
            <Text>{props.name || '—'}</Text>
          </Box>
          <Box>
            <Text variant="caption" color="var(--ggui-color-onSurfaceVariant)">Email</Text>
            <Text>{props.email || '—'}</Text>
          </Box>
          <Box>
            <Text variant="caption" color="var(--ggui-color-onSurfaceVariant)">Satisfaction</Text>
            <Text>{props.satisfactionLabel || '—'}</Text>
          </Box>
          <Box>
            <Text variant="caption" color="var(--ggui-color-onSurfaceVariant)">Feature interests</Text>
            <Text>{props.features.length ? props.features.join(', ') : 'None selected'}</Text>
          </Box>
          <Box>
            <Text variant="caption" color="var(--ggui-color-onSurfaceVariant)">Comments</Text>
            <Text>{props.comments || 'No comments provided'}</Text>
          </Box>
        </Stack>
      </Card>
    </Stack>
  );
}

export default function Component(props: Props) {
  // DO NOT EDIT wire hooks — auto-generated from the data contract
    // Actions — fire-and-forget to agent
  const submit = useAction<ActionSubmitPayload>('submit'); // Called with all collected answers as a structured object
  const totalSteps = 4;
  const [step, setStep] = useState(1);
  const [name, setName] = useState('');
  const [email, setEmail] = useState('');
  const [satisfaction, setSatisfaction] = useState('');
  const [features, setFeatures] = useState<string[]>([]);
  const [comments, setComments] = useState('');
  const [touched, setTouched] = useState({ name: false, email: false });
  const [submitted, setSubmitted] = useState(false);

  const nameError = touched.name && !name.trim() ? 'Name is required.' : '';
  const emailError = touched.email && !email.trim() ? 'Email is required.' : touched.email && !isValidEmail(email) ? 'Enter a valid email address.' : '';
  const satisfactionValue = Number(satisfaction);
  const satisfactionLabel = useMemo(() => {
    if (!satisfaction) return '';
    const index = Math.max(0, Math.min(props.satisfactionLabels.length - 1, satisfactionValue - 1));
    return props.satisfactionLabels[index] || `Rating ${satisfaction}`;
  }, [props.satisfactionLabels, satisfaction, satisfactionValue]);
  const commentsCount = comments.length;
  const commentsRemaining = 500 - commentsCount;
  const isStep1Valid = Boolean(name.trim()) && isValidEmail(email);
  const isStep2Valid = Boolean(satisfaction);
  const isStep3Valid = true;
  const isFinalReview = step === 4;

  const nextDisabled = (step === 1 && !isStep1Valid) || (step === 2 && !isStep2Valid) || (step === 3 && !isStep3Valid);

  const goNext = useCallback(() => {
    if (step === 1) setTouched({ name: true, email: true });
    if (nextDisabled) return;
    setStep((current) => Math.min(totalSteps, current + 1));
  }, [nextDisabled, step]);

  const goBack = useCallback(() => {
    setStep((current) => Math.max(1, current - 1));
  }, []);

  const handleSubmit = useCallback(() => {
    setTouched({ name: true, email: true });
    if (!isStep1Valid || !isStep2Valid) {
      setStep(isStep1Valid ? 2 : 1);
      return;
    }
    const payload: ActionSubmitPayload = {
      name: name.trim(),
      email: email.trim(),
      satisfaction: satisfactionValue,
      features,
      comments: comments.slice(0, 500),
    };
    if (submit) {
      submit(payload);
    }
    setSubmitted(true);
  }, [comments, email, features, isStep1Valid, isStep2Valid, name, satisfactionValue, submit]);

  useEffect(() => {
    if (step > totalSteps) setStep(totalSteps);
  }, [step, totalSteps]);

  const satisfactionOptions = useMemo(() => props.satisfactionLabels.map((label, index) => ({ value: String(index + 1), label })), [props.satisfactionLabels]);

  const commentsReady = comments.trim().length > 0 || comments.length === 0;
  return (
    <Container maxWidth="xl" padding="var(--ggui-spacing-6)">
      <Stack gap="var(--ggui-spacing-6)">
        <Card shadow="md" padding="var(--ggui-spacing-6)">
          <Stack gap="var(--ggui-spacing-4)">
            <StepHeader currentStep={step} totalSteps={totalSteps} />
            <Box
              padding="var(--ggui-spacing-4)"
              background="var(--ggui-color-surfaceVariant)"
              borderRadius="var(--ggui-shape-radius-lg)"
            >
              <Stack gap="var(--ggui-spacing-4)">
                {step === 1 && (
                  <>
                    <Heading level={3}>Tell us about you</Heading>
                    <Input
                      label="Name"
                      value={name}
                      onChange={(value) => {
                        setName(value);
                        if (!touched.name) setTouched((current) => ({ ...current, name: true }));
                      }}
                      required
                      error={nameError}
                      placeholder="Your name"
                    />
                    <Input
                      label="Email"
                      type="email"
                      value={email}
                      onChange={(value) => {
                        setEmail(value);
                        if (!touched.email) setTouched((current) => ({ ...current, email: true }));
                      }}
                      required
                      error={emailError}
                      placeholder="you@example.com"
                    />
                  </>
                )}

                {step === 2 && (
                  <>
                    <Heading level={3}>How satisfied are you?</Heading>
                    <RadioGroup
                      label="Satisfaction rating"
                      value={satisfaction}
                      onChange={setSatisfaction}
                      options={satisfactionOptions}
                      direction="vertical"
                    />
                  </>
                )}

                {step === 3 && (
                  <>
                    <Heading level={3}>What are you interested in?</Heading>
                    <Stack gap="var(--ggui-spacing-3)">
                      {props.featureOptions.length ? (
                        props.featureOptions.map((feature) => (
                          <Checkbox
                            key={feature}
                            label={feature}
                            checked={features.includes(feature)}
                            onChange={(checked) => {
                              setFeatures((current) =>
                                checked ? Array.from(new Set([...current, feature])) : current.filter((item) => item !== feature),
                              );
                            }}
                          />
                        ))
                      ) : (
                        <Alert variant="info" title="No feature options available">
                          There are no feature options provided for this survey.
                        </Alert>
                      )}
                    </Stack>
                  </>
                )}

                {step === 4 && (
                  <>
                    <Heading level={3}>Any final comments?</Heading>
                    <TextArea
                      label="Comments"
                      value={comments}
                      onChange={(value) => setComments(value.slice(0, 500))}
                      placeholder="Share any additional thoughts..."
                      rows={6}
                      maxLength={500}
                      showCount
                      helperText={`${commentsRemaining} characters remaining`}
                    />
                  </>
                )}

                {step === 5 && (
                  <AnswerReview
                    name={name.trim()}
                    email={email.trim()}
                    satisfactionLabel={satisfactionLabel}
                    features={features}
                    comments={comments.trim()}
                  />
                )}
              </Stack>
            </Box>

            {submitted && (
              <Alert variant="success" title="Survey submitted">
                Thanks for your responses. Your answers were sent successfully.
              </Alert>
            )}

            <Row align="center" justify="between">
              <Button variant="outline" onPress={goBack} disabled={step === 1}>
                Back
              </Button>
              <Row gap="var(--ggui-spacing-2)">
                {step < 4 ? (
                  <Button variant="primary" onPress={goNext} disabled={nextDisabled}>
                    Next
                  </Button>
                ) : (
                  <Button variant="primary" onPress={handleSubmit} disabled={!isStep1Valid || !isStep2Valid || !commentsReady}>
                    Submit
                  </Button>
                )}
              </Row>
            </Row>
              </Row>
            </Row>
          </Stack>
        </Card>
      </Stack>
    </Container>
  );
}

