}

export default function Component(props: Props) {
  // DO NOT EDIT wire hooks — auto-generated from the data contract
    // Actions — fire-and-forget to agent
  const taskUpdate = useAction<ActionTaskUpdatePayload>('taskUpdate'); // Called when a task is moved, edited, or created. Payload: { action, taskId, data }

  // Streams — real-time from agent (.latest, .all)
  const taskChanged = useStream<StreamTaskChanged>('taskChanged'); // A task was moved, edited, or created by another user — update it in the board

  const [tasks, setTasks] = useState(() => (props.tasks ?? []).map((task, index) => normalizeTask(task, index)));
  const [newTaskColumn, setNewTaskColumn] = useState('todo');
  const [newTaskTitle, setNewTaskTitle] = useState('');
  const [newTaskPriority, setNewTaskPriority] = useState<'low' | 'medium' | 'high'>('medium');
  const [addingForColumn, setAddingForColumn] = useState<string | null>(null);

  useEffect(() => {
    setTasks((props.tasks ?? []).map((task, index) => normalizeTask(task, index)));
  }, [props.tasks]);

  useEffect(() => {
    const incoming = taskChanged.latest?.task;
    if (!incoming?.id) return;
    setTasks((current) => {
      const next = [...current];
      const index = next.findIndex((task) => task.id === incoming.id);
      const normalized = normalizeTask(incoming, index >= 0 ? index : next.length);
      if (taskChanged.latest?.action === 'delete') {
        return next.filter((task) => task.id !== incoming.id);
      }
      if (index >= 0) {
        next[index] = { ...next[index], ...normalized };
      } else {
        next.push(normalized);
      }
      return next;
    });
  }, [taskChanged.latest]);

  const columnMeta = useMemo(() => {
    return (props.columns ?? []).map((column, index) => ({
      id: getColumnId(column, index),
      name: getColumnName(column, index),
    }));
  }, [props.columns]);

  const boardColumns = useMemo(() => {
    return columnMeta.map((column) => ({
      ...column,
      tasks: tasks.filter((task) => task.column === column.id),
    }));
  }, [columnMeta, tasks]);

  const totalTasks = tasks.length;
  const completedTasks = tasks.filter((task) => task.column === 'done').length;

  const moveTask = useCallback((taskId: string, nextColumn: string) => {
    setTasks((current) => current.map((task) => (task.id === taskId ? { ...task, column: nextColumn } : task)));
    taskUpdate({ action: 'move', taskId, data: { column: nextColumn } });
  }, [taskUpdate]);

  const editTask = useCallback((taskId: string, title: string) => {
    const column = currentColumnForTask(tasks, taskId);
    setTasks((current) => current.map((task) => (task.id === taskId ? { ...task, title } : task)));
    taskUpdate({ action: 'edit', taskId, data: { column, title } });
  }, [taskUpdate, tasks]);

  const createTask = useCallback((columnId: string) => {
    const title = newTaskTitle.trim();
    if (!title) return;
    const id = `task-${Date.now()}`;
    const nextTask = { id, title, priority: newTaskPriority, assignee: '', column: 'todo', dueDate: '' };
    setTasks((current) => [...current, nextTask]);
    setNewTaskTitle('');
    setNewTaskPriority('medium');
    setAddingForColumn(null);
    taskUpdate({ action: 'create', taskId: id, data: { column: 'todo' } });
  }, [newTaskPriority, newTaskTitle, taskUpdate]);

  function currentColumnForTask(list: { id: string; column: string }[], taskId: string) {
    return list.find((task) => task.id === taskId)?.column ?? 'todo';
  }

  return (
    <Container maxWidth="xl" padding="var(--ggui-spacing-6)">
      <Stack gap="var(--ggui-spacing-6)">
        <Card padding="var(--ggui-spacing-5)" shadow="sm" radius="lg">
          <Row align="center" justify="between" wrap>
            <Stack gap="var(--ggui-spacing-1)">
              <Heading level={2}>Kanban Board</Heading>
              <Text color="var(--ggui-color-onSurfaceVariant)">Manage tasks across your workflow in real time.</Text>
            </Stack>
            <Row gap="var(--ggui-spacing-3)" wrap>
              <Badge variant="primary">Total {totalTasks}</Badge>
              <Badge variant="success">Completed {completedTasks}</Badge>
            </Row>
          </Row>
        </Card>
        <Row gap="var(--ggui-spacing-4)" wrap>
          {boardColumns.map((column) => (
            <Card key={column.id} padding="var(--ggui-spacing-4)" shadow="sm" radius="lg">
              <Stack gap="var(--ggui-spacing-4)">
                <Row justify="between" align="center">
                  <Heading level={3}>{column.name}</Heading>
                  <Badge variant="secondary">{column.tasks.length}</Badge>
                </Row>
                <Stack gap="var(--ggui-spacing-3)">
                  {column.tasks.length === 0 ? (
                    <Box padding="var(--ggui-spacing-4)" background="var(--ggui-color-surfaceVariant)" borderRadius="var(--ggui-shape-radius-md)">
                      <Text color="var(--ggui-color-onSurfaceVariant)">No tasks in this column.</Text>
                    </Box>
                  ) : (
                    column.tasks.map((task) => (
                      <TaskCard key={task.id} task={task} columnId={column.id} onMove={moveTask} onEdit={editTask} />
                    ))
                  )}
                </Stack>
                {addingForColumn === column.id ? (
                  <Card padding="var(--ggui-spacing-4)" shadow="none" radius="md" border>
                    <Stack gap="var(--ggui-spacing-3)">
                      <Input label="New task title" value={newTaskTitle} onChange={setNewTaskTitle} placeholder="Enter task title" />
                      <Select label="Priority" value={newTaskPriority} onChange={(value) => setNewTaskPriority(value as 'low' | 'medium' | 'high')} options={PRIORITY_OPTIONS as unknown as Array<{ value: string; label: string }>} />
                      <Row gap="var(--ggui-spacing-2)">
                        <Button variant="primary" size="sm" onClick={() => createTask(column.id)}>Add Task</Button>
                        <Button variant="ghost" size="sm" onClick={() => setAddingForColumn(null)}>Cancel</Button>
                      </Row>
                    </Stack>
                  </Card>
                ) : (
                  <Button variant="outline" fullWidth onClick={() => { setAddingForColumn(column.id); setNewTaskColumn(column.id); }}>Add Task</Button>
                )}
              </Stack>
            </Card>
          ))}
        </Row>
      </Stack>
    </Container>
  );
}

