const CATEGORY_TOKENS: Record<string, { bg: string; fg: string; border: string }> = {
  'alkali metal': { bg: 'var(--ggui-color-warning-100)', fg: 'var(--ggui-color-warning-800)', border: 'var(--ggui-color-warning-200)' },
  'alkaline earth metal': { bg: 'var(--ggui-color-warning-50)', fg: 'var(--ggui-color-warning-800)', border: 'var(--ggui-color-warning-200)' },
  'transition metal': { bg: 'var(--ggui-color-primary-50)', fg: 'var(--ggui-color-primary-800)', border: 'var(--ggui-color-primary-200)' },
  'post-transition metal': { bg: 'var(--ggui-color-info-50)', fg: 'var(--ggui-color-info-800)', border: 'var(--ggui-color-info-200)' },
  metalloid: { bg: 'var(--ggui-color-success-50)', fg: 'var(--ggui-color-success-800)', border: 'var(--ggui-color-success-200)' },
  nonmetal: { bg: 'var(--ggui-color-success-100)', fg: 'var(--ggui-color-success-800)', border: 'var(--ggui-color-success-200)' },
  'reactive nonmetal': { bg: 'var(--ggui-color-success-100)', fg: 'var(--ggui-color-success-800)', border: 'var(--ggui-color-success-200)' },
  halogen: { bg: 'var(--ggui-color-error-50)', fg: 'var(--ggui-color-error-800)', border: 'var(--ggui-color-error-200)' },
  'noble gas': { bg: 'var(--ggui-color-primary-100)', fg: 'var(--ggui-color-primary-800)', border: 'var(--ggui-color-primary-200)' },
  lanthanide: { bg: 'var(--ggui-color-warning-100)', fg: 'var(--ggui-color-warning-800)', border: 'var(--ggui-color-warning-200)' },
  actinide: { bg: 'var(--ggui-color-error-100)', fg: 'var(--ggui-color-error-800)', border: 'var(--ggui-color-error-200)' },
  unknown: { bg: 'var(--ggui-color-surfaceVariant)', fg: 'var(--ggui-color-onSurfaceVariant)', border: 'var(--ggui-color-outlineVariant)' },
};

function getCategoryKey(category?: string) {
  const normalized = (category || 'unknown').toLowerCase();
  if (CATEGORY_TOKENS[normalized]) return normalized;
  if (normalized.includes('alkali')) return 'alkali metal';
  if (normalized.includes('alkaline')) return 'alkaline earth metal';
  if (normalized.includes('transition')) return 'transition metal';
  if (normalized.includes('post-transition')) return 'post-transition metal';
  if (normalized.includes('metalloid')) return 'metalloid';
  if (normalized.includes('halogen')) return 'halogen';
  if (normalized.includes('noble')) return 'noble gas';
  if (normalized.includes('lanthan')) return 'lanthanide';
  if (normalized.includes('actin')) return 'actinide';
  if (normalized.includes('nonmetal')) return normalized.includes('reactive') ? 'reactive nonmetal' : 'nonmetal';
  return 'unknown';
}

function formatWeight(weight?: number) {
  if (typeof weight !== 'number' || Number.isNaN(weight)) return '—';
  return weight.toString();
}

function ElementCell({ element, selected, onSelect }: { element: { atomicNumber?: number; symbol?: string; name?: string; atomicWeight?: number; category?: string; row?: number; col?: number }; selected: boolean; onSelect: () => void; }) {
  const categoryKey = getCategoryKey(element.category);
  const categoryTokens = CATEGORY_TOKENS[categoryKey] || CATEGORY_TOKENS.unknown;
  return (
