        <Text variant="caption" align="center" truncate color="inherit">{element.name ?? 'Unknown'}</Text>
      </Stack>
    </Card>
  );
}

function LegendItem({ category, label }: { category: string; label: string }) {
  const tokens = CATEGORY_TOKENS[category] || CATEGORY_TOKENS.unknown;
  return (
