export default function Component(props: Props) {
  const [query, setQuery] = useState('');
  const [selectedKey, setSelectedKey] = useState<string>('');

  const elements = props.elements || [];

  const filteredElements = useMemo(() => {
    const q = query.trim().toLowerCase();
    if (!q) return elements;
    return elements.filter((element) => {
      const name = (element.name || '').toLowerCase();
      const symbol = (element.symbol || '').toLowerCase();
      return name.includes(q) || symbol.includes(q);
    });
  }, [elements, query]);

  useEffect(() => {
    if (!filteredElements.length) {
      setSelectedKey('');
      return;
    }
    if (selectedKey && filteredElements.some((e) => `${e.atomicNumber ?? ''}-${e.symbol ?? ''}` === selectedKey)) return;
    const first = filteredElements[0];
    setSelectedKey(`${first.atomicNumber ?? ''}-${first.symbol ?? ''}`);
  }, [filteredElements, selectedKey]);

  const selectedElement = useMemo(() => filteredElements.find((e) => `${e.atomicNumber ?? ''}-${e.symbol ?? ''}` === selectedKey) || null, [filteredElements, selectedKey]);

  const legendCategories = useMemo(() => {
    const seen = new Set<string>();
    const items: Array<{ key: string; label: string }> = [];
    elements.forEach((element) => {
      const key = getCategoryKey(element.category);
      if (!seen.has(key)) {
        seen.add(key);
        items.push({ key, label: element.category || 'Unknown' });
      }
    });
    if (!seen.has('unknown')) items.push({ key: 'unknown', label: 'Unknown' });
    return items;
  }, [elements]);

  return (
    <Container maxWidth="xl" padding="var(--ggui-spacing-6)">
      <Stack gap="var(--ggui-spacing-6)">
        <Card padding="var(--ggui-spacing-6)" shadow="md">
          <Stack gap="var(--ggui-spacing-4)">
            <Stack gap="var(--ggui-spacing-2)">
              <Heading level={1}>Periodic Table</Heading>
              <Text color="var(--ggui-color-onSurfaceVariant)">Explore the elements by searching by name or symbol, then click any element for details.</Text>
            </Stack>
            <Input label="Search elements" type="search" placeholder="Search by name or symbol" value={query} onChange={setQuery} helperText="Case-insensitive search across element names and symbols." />
          </Stack>
        </Card>

        <Card padding="var(--ggui-spacing-6)" shadow="sm">
          <Stack gap="var(--ggui-spacing-4)">
            <Row gap="var(--ggui-spacing-4)" wrap>
              {legendCategories.map((item) => (
                <LegendItem key={item.key} category={item.key} label={item.label} />
              ))}
            </Row>
            <Box style={{ display: 'grid', gridTemplateColumns: 'repeat(18, minmax(0, 1fr))', gap: 'var(--ggui-spacing-2)', alignItems: 'stretch' } as React.CSSProperties}>
              {filteredElements.map((element) => {
                const key = `${element.atomicNumber ?? ''}-${element.symbol ?? ''}`;
                return <ElementCell key={key} element={element} selected={selectedKey === key} onSelect={() => setSelectedKey(key)} />;
              })}
            </Box>
            {!filteredElements.length && <Alert variant="info" title="No elements found">Try a different search term to find an element.</Alert>}
          </Stack>
        </Card>

        <Card padding="var(--ggui-spacing-6)" shadow="sm">
          <Stack gap="var(--ggui-spacing-4)">
            <Heading level={3}>Element details</Heading>
            {selectedElement ? (
              <Stack gap="var(--ggui-spacing-3)">
                <Row gap="var(--ggui-spacing-3)" align="center" wrap>
                  <Badge variant="primary">{selectedElement.atomicNumber ?? '—'}</Badge>
                  <Badge variant="secondary">{selectedElement.category || 'Unknown'}</Badge>
                </Row>
                <Stack gap="var(--ggui-spacing-2)"><Text variant="caption" color="var(--ggui-color-onSurfaceVariant)">Name</Text><Text variant="bodyLarge" weight="bold">{selectedElement.name ?? 'Unknown'}</Text></Stack>
                <Stack gap="var(--ggui-spacing-2)"><Text variant="caption" color="var(--ggui-color-onSurfaceVariant)">Symbol</Text><Text variant="bodyLarge" weight="bold">{selectedElement.symbol ?? '—'}</Text></Stack>
                <Stack gap="var(--ggui-spacing-2)"><Text variant="caption" color="var(--ggui-color-onSurfaceVariant)">Atomic number</Text><Text>{selectedElement.atomicNumber ?? '—'}</Text></Stack>
                <Stack gap="var(--ggui-spacing-2)"><Text variant="caption" color="var(--ggui-color-onSurfaceVariant)">Atomic weight</Text><Text>{formatWeight(selectedElement.atomicWeight)}</Text></Stack>
                <Stack gap="var(--ggui-spacing-2)"><Text variant="caption" color="var(--ggui-color-onSurfaceVariant)">Category</Text><Text>{selectedElement.category || 'Unknown'}</Text></Stack>
              </Stack>
            ) : (
              <Text color="var(--ggui-color-onSurfaceVariant)">Select an element to see its details.</Text>
            )}
          </Stack>
        </Card>
      </Stack>
    </Container>
  );
}

