function formatCurrencyAmount(amount: number, currency?: string) {
  const symbolMap: Record<string, string> = {
    USD: '$',
    EUR: '€',
    GBP: '£',
    JPY: '¥',
    CAD: 'C$',
    AUD: 'A$',
    INR: '₹',
  };
  if (currency && symbolMap[currency.toUpperCase()]) {
    return `${symbolMap[currency.toUpperCase()]}${amount.toFixed(2)}`;
  }
  return `${currency ?? ''}${currency ? ' ' : ''}${amount.toFixed(2)}`.trim();
}

function formatReviewDate(value: unknown) {
  if (value instanceof Date) return value.toLocaleDateString();
  if (typeof value === 'string' || typeof value === 'number') {
    const parsed = new Date(value);
    if (!Number.isNaN(parsed.getTime())) return parsed.toLocaleDateString();
    return String(value);
  }
  return '';
}

function toNumber(value: unknown, fallback = 0) {
  const num = typeof value === 'number' ? value : Number(value);
  return Number.isFinite(num) ? num : fallback;
}

function toStringValue(value: unknown, fallback = '') {
  if (typeof value === 'string') return value;
  if (typeof value === 'number' || typeof value === 'boolean') return String(value);
  return fallback;
}

function normalizeSpecifications(specifications: unknown[] = []) {
  return (Array.isArray(specifications) ? specifications : []).map((item, index) => {
    if (item && typeof item === 'object' && !Array.isArray(item)) {
      const entries = Object.entries(item as Record<string, unknown>);
      const [firstKey, firstValue] = entries[0] ?? [`Spec ${index + 1}`, ''];
      const [secondKey, secondValue] = entries[1] ?? ['', ''];
      return { key: String(firstKey), label: String(secondKey || firstKey), value: String(firstValue ?? secondValue ?? '') };
    }
    return { key: `spec-${index}`, label: `Spec ${index + 1}`, value: String(item ?? '') };
  });
}

function normalizeReviews(reviews: unknown[] = []) {
  return (Array.isArray(reviews) ? reviews : []).map((review, index) => {
    if (review && typeof review === 'object' && !Array.isArray(review)) {
      const r = review as Record<string, unknown>;
      return {
        id: String(r.id ?? `review-${index}`),
        author: toStringValue(r.author ?? r.name ?? 'Anonymous', 'Anonymous'),
        rating: Math.max(0, Math.min(5, Math.round(toNumber(r.rating, 0)))),
        text: toStringValue(r.text ?? r.content ?? '', ''),
        date: formatReviewDate(r.date ?? r.timestamp),
      };
    }
    return { id: `review-${index}`, author: 'Anonymous', rating: 0, text: String(review ?? ''), date: '' };
  });
