function formatTimestamp(value?: string): string {
  if (!value) return '—';
  const parsed = new Date(value);
  if (Number.isNaN(parsed.getTime())) return value;
  return parsed.toLocaleTimeString([], { hour: 'numeric', minute: '2-digit' });
}

function makeMessageId(sender: string | undefined, text: string | undefined, timestamp: string | undefined, index: number): string {
  return `${sender ?? 'unknown'}-${timestamp ?? 'no-time'}-${text ?? 'empty'}-${index}`;
}

function areSameSender(a?: { sender?: string }, b?: { sender?: string }): boolean {
  return Boolean(a?.sender && b?.sender && a.sender === b.sender);
}

