  const sendMessage = useAction<ActionSendMessagePayload>('sendMessage'); // Called when user sends a message. Payload: { text, timestamp }

  // Streams — real-time from agent (.latest, .all)
  const message = useStream<StreamMessage>('message') ?? { latest: null, all: [] }; // New message from another participant — append to message list
  const typing = useStream<StreamTyping>('typing') ?? { latest: null, all: [] }; // Typing indicator — show/hide based on active flag

  const [draft, setDraft] = useState('');
  const [messages, setMessages] = useState<Array<{ sender?: string; text?: string; timestamp?: string; id: string }>>(() =>
    (props.messages ?? []).map((m, index) => ({ ...m, id: makeMessageId(m.sender, m.text, m.timestamp, index) })),
  );
  const [typingBySender, setTypingBySender] = useState<Record<string, boolean>>({});
  const listEndRef = useRef<HTMLDivElement | null>(null);

  useEffect(() => {
    setMessages((props.messages ?? []).map((m, index) => ({ ...m, id: makeMessageId(m.sender, m.text, m.timestamp, index) })));
  }, [props.messages]);

  useEffect(() => {
    const incomingMessages = (message?.all ?? []) as StreamMessage[];
    if (!incomingMessages.length) return;
    setMessages((prev) => {
      const existingKeys = new Set(prev.map((item) => `${item.sender ?? ''}|${item.timestamp ?? ''}|${item.text ?? ''}`));
      const next = [...prev];
      incomingMessages.forEach((item, index) => {
        const key = `${item.sender ?? ''}|${item.timestamp ?? ''}|${item.text ?? ''}`;
        if (!existingKeys.has(key)) {
          existingKeys.add(key);
          next.push({ ...item, id: makeMessageId(item.sender, item.text, item.timestamp, prev.length + index) });
        }
      });
      return next;
    });
  }, [message?.all]);

  const typingState = useMemo(() => {
    const active = (typing?.all ?? []).reduce<Record<string, boolean>>((acc, event) => {
      if (event?.sender) acc[event.sender] = Boolean(event.active);
      return acc;
    }, {});
    setTypingBySender(active);
    const activeSenders = Object.keys(active).filter((sender) => active[sender] && sender !== props.currentUser);
    return activeSenders.length ? { sender: activeSenders[0], active: true } : null;
  }, [typing?.all, props.currentUser]);

