                ) : (
                  <Badge variant="default">Live</Badge>
                )}
              </Row>
            </Row>
          </Box>

          <Box
            padding="var(--ggui-spacing-4)"
            background="var(--ggui-color-surface)"
            style={{ minHeight: '55vh', display: 'flex', flexDirection: 'column' }}
          >
            <Box
              style={{ flex: 1, overflowY: 'auto' }}
