export default function Component(props: Props) {
  // DO NOT EDIT wire hooks — auto-generated from the data contract

  // Streams — real-time from agent (.latest, .all)
  const priceUpdate = useStream<StreamPriceUpdate>('priceUpdate'); // Updated price data for one or more stocks
  const marketStatus = useStream<StreamMarketStatus>('marketStatus'); // Market open/closed status update
  const [nowTick, setNowTick] = useState(Date.now());
  const [selectedSymbol, setSelectedSymbol] = useState<string>('');

  useEffect(() => {
    const id = setInterval(() => setNowTick(Date.now()), 1000);
    return () => clearInterval(id);
  }, []);

  const liveStocks = useMemo(() => {
    const baseStocks = (props.stocks || []).map((stock) => ({
      symbol: stock.symbol ?? '',
      name: stock.name ?? '',
      price: stock.price ?? 0,
      change: stock.change ?? 0,
      changePercent: stock.changePercent ?? 0,
    }));
    const update = priceUpdate.latest;
    if (!update?.symbol) {
      return baseStocks;
    }
    return baseStocks.map((stock) => {
      if (stock.symbol !== update.symbol) {
        return stock;
      }
      return {
        ...stock,
        price: update.price ?? stock.price,
        change: update.change ?? stock.change,
        changePercent: update.changePercent ?? stock.changePercent,
      };
    });
  }, [props.stocks, priceUpdate.latest]);

  const lastUpdatedLabel = useMemo(() => {
    if (marketStatus.latest?.timestamp) {
      return marketStatus.latest.timestamp;
    }
    return new Date(nowTick).toLocaleTimeString([], { hour: '2-digit', minute: '2-digit', second: '2-digit' });
  }, [marketStatus.latest?.timestamp, nowTick]);

  const selectedStock = liveStocks.find((stock) => stock.symbol === selectedSymbol) || liveStocks[0] || null;

  return (
    <Container maxWidth="xl" padding="var(--ggui-spacing-6)">
      <Stack gap="var(--ggui-spacing-6)">
        <Stack gap="var(--ggui-spacing-3)">
