            <Stack gap="var(--ggui-spacing-1)">
              <Heading level={1}>Market Watch</Heading>
              <Text color="var(--ggui-color-onSurfaceVariant)">
                Live stock prices with stream-driven updates.
              </Text>
            </Stack>
            <Stack gap="var(--ggui-spacing-1)" align="end">
              <Text variant="caption" color="var(--ggui-color-onSurfaceVariant)">
                Last Updated
              </Text>
              <Text variant="bodySmall" weight="semibold">
                {lastUpdatedLabel}
              </Text>
            </Stack>
          </Row>
          <Alert variant="info">
            {marketStatus.latest?.status
              ? `Market status: ${marketStatus.latest.status}`
              : 'Waiting for live market status updates.'}
          </Alert>
        </Stack>

        <Card shadow="sm" border radius="xl" padding="var(--ggui-spacing-6)">
          <Stack gap="var(--ggui-spacing-4)">
            <Row align="center" justify="between" gap="var(--ggui-spacing-3)">
              <Heading level={2}>Stocks</Heading>
              <Badge variant="default">{liveStocks.length} tracked</Badge>
            </Row>
            <Box
              style={{
                display: 'grid',
                gridTemplateColumns: 'repeat(auto-fit, minmax(240px, 1fr))',
                gap: 'var(--ggui-spacing-4)',
              }}
            >
              {liveStocks.map((stock, index) => {
                const isSelected = selectedStock?.symbol === stock.symbol;
                return (
                  <Box key={`${stock.symbol}-${index}`}>
                    <Card
                      as={Clickable}
                      onClick={() => setSelectedSymbol(stock.symbol)}
                      shadow="sm"
                      border
                      radius="lg"
                      padding="var(--ggui-spacing-4)"
                      style={{
                        outline: isSelected ? '2px solid var(--ggui-color-primary-600)' : 'none',
                        outlineOffset: '2px',
                      }}
                    >
                      <StockCard stock={stock} highlightKey={`${stock.symbol}-${index}`} />
                    </Card>
                  </Box>
                );
              })}
            </Box>
          </Stack>
        </Card>

        {selectedStock ? (
          <Card padding="var(--ggui-spacing-4)" border radius="lg">
            <Stack gap="var(--ggui-spacing-2)">
              <Heading level={3}>Selected Stock</Heading>
              <Text color="var(--ggui-color-onSurfaceVariant)">
                {selectedStock.symbol} · {selectedStock.name}
              </Text>
            </Stack>
          </Card>
        ) : null}
      </Stack>
    </Container>
  );
}

// DO NOT EDIT imports — all available components are pre-imported.
// prettier-ignore-start
import React, { useState, useCallback, useMemo, useEffect, useRef } from 'react';
// Layout: Container, Card, Stack, Row, Box, Divider, Spacer
// Typography: Text, Heading | Inputs: Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider
// Display: Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip | Data: Table, Tabs, Accordion
import { Container, Card, Stack, Row, Box, Divider, Spacer, Text, Heading, Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider, Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip, Table, Tabs, Toast, Accordion } from '@ggui-ai/design/primitives';
// Components: SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination
import { SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination } from '@ggui-ai/design/components';
// Compositions: Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, Modal, Footer, Hero
import { Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, FileUploader, UserProfileCard, NotificationCenter, Modal, CommandPalette, Footer, Hero } from '@ggui-ai/design/compositions';
// Interaction wrappers: use as={Clickable} on primitives for onClick, as={Hoverable} for hover, as={Pressable} for press
import { Clickable, Hoverable, Pressable } from '@ggui-ai/design/interact';
import { useAction } from '@ggui-ai/wire';
// prettier-ignore-end

// DO NOT EDIT Props — auto-generated from the data contract
// DO NOT EDIT — generated from data contract. Changing this will fail validation.
interface Props {
  initialProfile: { name?: string; email?: string; avatar?: string; role?: string; emailNotifications?: boolean; theme?: string }; // Pre-filled profile data for editing (all fields optional)
  avatarOptions: string[]; // Available avatar emojis to choose from
  roleOptions: string[]; // Available role options for the dropdown
}

// DO NOT EDIT — action payload types generated from action contract.
/** Action payload: Called with all profile data when user completes onboarding */
type ActionCompletePayload = { name: string; email: string; avatar: string; role: string; emailNotifications: boolean; theme: string };





function avatarLabel(avatar: string | undefined): string {
  return avatar || '🙂';
}

function isValidEmail(email: string): boolean {
  return /^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(email.trim());
}

function normalizeRole(role: string | undefined, roleOptions: string[]): string {
  if (role && roleOptions.includes(role)) return role;
  return roleOptions[0] || '';
}

export default function Component(props: Props) {
  // DO NOT EDIT wire hooks — auto-generated from the data contract
  // Actions — fire-and-forget to agent
  const complete = useAction<ActionCompletePayload>('complete');
  const [step, setStep] = useState(1);
  const [name, setName] = useState(props.initialProfile.name || '');
  const [email, setEmail] = useState(props.initialProfile.email || '');
  const [avatar, setAvatar] = useState(props.initialProfile.avatar || props.avatarOptions[0] || '🙂');
  const [role, setRole] = useState(normalizeRole(props.initialProfile.role, props.roleOptions));
  const [emailNotifications, setEmailNotifications] = useState(props.initialProfile.emailNotifications ?? true);
  const [theme, setTheme] = useState(props.initialProfile.theme === 'dark' ? 'dark' : 'light');
  const [showErrors, setShowErrors] = useState(false);
  const [submitted, setSubmitted] = useState(false);

  useEffect(() => {
    setName(props.initialProfile.name || '');
    setEmail(props.initialProfile.email || '');
    setAvatar(props.initialProfile.avatar || props.avatarOptions[0] || '🙂');
    setRole(normalizeRole(props.initialProfile.role, props.roleOptions));
    setEmailNotifications(props.initialProfile.emailNotifications ?? true);
    setTheme(props.initialProfile.theme === 'dark' ? 'dark' : 'light');
    setStep(1);
    setShowErrors(false);
    setSubmitted(false);
  }, [props.initialProfile, props.avatarOptions, props.roleOptions]);

  const emailValid = useMemo(() => isValidEmail(email), [email]);
  const nameValid = useMemo(() => name.trim().length > 0, [name]);
  const step1Valid = nameValid && emailValid && Boolean(avatar);
  const step2Valid = Boolean(role) && (theme === 'light' || theme === 'dark');
  const canGoNext = step === 1 ? step1Valid : step === 2 ? step2Valid : false;

  const fieldErrors = useMemo(() => ({
    name: showErrors && !nameValid ? 'Name is required.' : '',
    email: showErrors && !email ? 'Email is required.' : showErrors && email && !emailValid ? 'Please enter a valid email address.' : '',
  }), [email, emailValid, nameValid, showErrors, name, email]);

  const progressValue = (step / 3) * 100;
  const summaryRows = [
    { label: 'Name', value: name || '—' },
    { label: 'Email', value: email || '—' },
    { label: 'Avatar', value: avatar || '—' },
    { label: 'Role', value: role || '—' },
    { label: 'Notifications', value: emailNotifications ? 'On' : 'Off' },
    { label: 'Theme', value: theme },
  ];

  const goNext = useCallback(() => {
    setShowErrors(true);
    if (step === 1 && !step1Valid) return;
    if (step === 2 && !step2Valid) return;
    setStep((s) => Math.min(3, s + 1));
  }, [step, step1Valid, step2Valid]);

  const goBack = useCallback(() => {
    setStep((s) => Math.max(1, s - 1));
  }, []);

  const handleComplete = useCallback(() => {
    if (!step1Valid || !step2Valid) {
      setShowErrors(true);
      setStep(!step1Valid ? 1 : 2);
      return;
    }
    const payload: ActionCompletePayload = { name: name.trim(), email: email.trim(), avatar, role, emailNotifications, theme };
    complete(payload);
    setSubmitted(true);
  }, [avatar, complete, email, emailNotifications, name, role, step1Valid, step2Valid, theme]);

  const stepTitle = step === 1 ? 'Profile Setup' : step === 2 ? 'Preferences' : 'Review & Confirm';
  const stepSubtitle = step === 1
    ? 'Tell us who you are.'
    : step === 2
      ? 'Set your preferences.'
      : 'Review everything before completing setup.';

  return (
    <Container maxWidth="xl" padding="var(--ggui-spacing-6)">
      <Stack gap="var(--ggui-spacing-6)">
        <Card padding="var(--ggui-spacing-6)" shadow="md">
          <Stack gap="var(--ggui-spacing-4)">
            <Row align="center" justify="between" gap="var(--ggui-spacing-4)">
              <Stack gap="var(--ggui-spacing-1)">
                <Heading level={2}>Onboarding Wizard</Heading>
                <Text color="var(--ggui-color-onSurfaceVariant)">{stepTitle} — {stepSubtitle}</Text>
              </Stack>
              <Badge variant={step === 3 ? 'success' : 'primary'} size="md">Step {step}/3</Badge>
            </Row>
            <Progress value={progressValue} showLabel />
          </Stack>
        </Card>

        {submitted ? (
          <Alert variant="success" title="Setup complete">
            Your profile was submitted successfully.
          </Alert>
        ) : null}

        <Card padding="var(--ggui-spacing-6)" shadow="md">
          <Stack gap="var(--ggui-spacing-6)">
            <Box>
              {step === 1 && (
                <Stack gap="var(--ggui-spacing-4)">
                  <Heading level={3}>Profile Setup</Heading>
                  <Input label="Name" value={name} onChange={(v) => setName(v)} required placeholder="Your full name" error={fieldErrors.name} />
                  <Input label="Email" type="email" value={email} onChange={(v) => setEmail(v)} required placeholder="you@example.com" error={fieldErrors.email} />
                  <Stack gap="var(--ggui-spacing-2)">
                    <Text variant="label" is="div">Avatar</Text>
                    <Row gap="var(--ggui-spacing-2)" wrap>
                      {(props.avatarOptions || []).map((item) => {
                        const selected = avatar === item;
                        return (
                          <Box
                            key={item}
                            as={Clickable}
                            role="radio"
                            aria-checked={selected}
                            tabIndex={0}
                            onClick={() => setAvatar(item)}
                            onKeyDown={(event) => {
                              if (event.key === 'Enter' || event.key === ' ') {
                                event.preventDefault();
                                setAvatar(item);
                              }
                            }}
                            padding="var(--ggui-spacing-3)"
                            borderRadius="var(--ggui-shape-radius-md)"
                            style={{
                              border: '1px solid',
                              borderColor: selected ? 'var(--ggui-color-primary-600)' : 'var(--ggui-color-outlineVariant)',
                              background: selected ? 'var(--ggui-color-primary-50)' : 'var(--ggui-color-surface)',
                              transition: 'all 200ms ease-in-out',
                            }}
                          >
                            <Stack gap="var(--ggui-spacing-2)" align="center">
                              <Text variant="bodyLarge">{avatarLabel(item)}</Text>
                              <Text variant="caption" color="var(--ggui-color-onSurfaceVariant)">{selected ? 'Selected' : 'Choose'}</Text>
                            </Stack>
                          </Box>
                        );
                      })}
                    </Row>
                  </Stack>
                </Stack>
              )}

              {step === 2 && (
                <Stack gap="var(--ggui-spacing-4)">
                  <Heading level={3}>Preferences</Heading>
                  <Select
                    label="Role"
                    value={role}
                    onChange={setRole}
                    options={(props.roleOptions || []).map((r) => ({ value: r, label: r }))}
                    placeholder="Select a role"
                    required
                  />
                  <Toggle
                    label="Email notifications"
                    checked={emailNotifications}
                    onChange={setEmailNotifications}
                    size="md"
                  />
                  <Box padding="var(--ggui-spacing-4)" background="var(--ggui-color-surfaceVariant)" borderRadius="var(--ggui-shape-radius-lg)">
                    <Stack gap="var(--ggui-spacing-2)">
                      <Row align="center" justify="between">
                        <Text variant="label">Theme preference</Text>
                        <Badge variant={theme === 'dark' ? 'secondary' : 'primary'} size="sm">{theme}</Badge>
                      </Row>
                      <Toggle label="Dark theme" checked={theme === 'dark'} onChange={(checked) => setTheme(checked ? 'dark' : 'light')} size="md" />
                    </Stack>
                  </Box>
                </Stack>
              )}

              {step === 3 && (
                <Stack gap="var(--ggui-spacing-4)">
                  <Heading level={3}>Review & Confirm</Heading>
                  <Text color="var(--ggui-color-onSurfaceVariant)">Make sure everything looks good before finishing.</Text>
                  <Card padding="var(--ggui-spacing-4)" shadow="sm" border>
                    <Stack gap="var(--ggui-spacing-3)">
                      {summaryRows.map((row) => (
                        <Row key={row.label} justify="between" gap="var(--ggui-spacing-4)">
                          <Text variant="label" color="var(--ggui-color-onSurfaceVariant)">{row.label}</Text>
                          <Text align="right">{row.value}</Text>
                        </Row>
                      ))}
                    </Stack>
                  </Card>
                  <Row gap="var(--ggui-spacing-3)" align="center">
                    <Avatar name={name || 'Avatar'} size="lg" />
                    <Stack gap="var(--ggui-spacing-1)">
                      <Text variant="label">Preview</Text>
                      <Text color="var(--ggui-color-onSurfaceVariant)">{email}</Text>
                    </Stack>
                  </Row>
                </Stack>
              )}
            </Box>

            <Divider />

            <Row justify="between" align="center" gap="var(--ggui-spacing-3)">
              <Button variant="ghost" onClick={goBack} disabled={step === 1}>Go Back</Button>
              <Spacer size="flex" />
              {step < 3 ? (
                <Button variant="primary" onClick={goNext} disabled={!canGoNext}>Next</Button>
              ) : (
                <Button variant="primary" onClick={handleComplete}>Complete Setup</Button>
              )}
            </Row>
          </Stack>
        </Card>
      </Stack>
    </Container>
  );
}
